const { ethers } = require('ethers');

class TokenSwapper {
  constructor(provider, signer) {
    this.provider = provider;
    this.signer = signer;
    this.signerAddress = null;
  }

  async initialize() {
    this.signerAddress = await this.signer.getAddress();
  }

  async getERC20TokenContract(tokenAddress) {
    const abi = [
      "function balanceOf(address owner) view returns (uint256)",
      "function approve(address spender, uint256 value) returns (bool)",
      "function allowance(address owner, address spender) view returns (uint256)",
      "function decimals() view returns (uint8)"
    ];
    return new ethers.Contract(tokenAddress, abi, this.signer);
  }

  async getSwapContract(contractAddress, routerAbi) {
    return new ethers.Contract(contractAddress, routerAbi, this.signer);
  }

  async approveToken(tokenAddress, spenderAddress, amount = ethers.constants.MaxUint256) {
    try {
      const tokenContract = await this.getERC20TokenContract(tokenAddress);
      const tx = await tokenContract.approve(spenderAddress, amount);
      await tx.wait();
      return tx;
    } catch (error) {
      throw new Error(`Approval failed: ${error.message}`);
    }
  }

  async checkAllowance(tokenAddress, spenderAddress) {
    try {
      const tokenContract = await this.getERC20TokenContract(tokenAddress);
      const allowance = await tokenContract.allowance(this.signerAddress, spenderAddress);
      return allowance;
    } catch (error) {
      throw new Error(`Allowance check failed: ${error.message}`);
    }
  }

  async swapTokens(
    tokenInAddress,
    tokenOutAddress,
    amountIn,
    amountOutMin,
    path,
    to,
    deadline
  ) {
    try {
      const routerAbi = [
        "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)"
      ];
      
      const routerContract = await this.getSwapContract(
        "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D",
        routerAbi
      );

      const tx = await routerContract.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        to,
        deadline
      );

      return await tx.wait();
    } catch (error) {
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async getAmountsOut(amountIn, path) {
    try {
      const routerAbi = [
        "function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts)"
      ];
      
      const routerContract = await this.getSwapContract(
        "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D",
        routerAbi
      );

      const amounts = await routerContract.getAmountsOut(amountIn, path);
      return amounts;
    } catch (error) {
      throw new Error(`Amounts out calculation failed: ${error.message}`);
    }
  }

  async getBalance(tokenAddress) {
    try {
      const tokenContract = await this.getERC20TokenContract(tokenAddress);
      const balance = await tokenContract.balanceOf(this.signerAddress);
      return balance;
    } catch (error) {
      throw new Error(`Balance check failed: ${error.message}`);
    }
  }

  async ensureApproval(tokenAddress, spenderAddress, amount) {
    try {
      const allowance = await this.checkAllowance(tokenAddress, spenderAddress);
      if (allowance.lt(amount)) {
        await this.approveToken(tokenAddress, spenderAddress);
      }
    } catch (error) {
      throw new Error(`Approval check failed: ${error.message}`);
    }
  }
}

module.exports = TokenSwapper;